1	type Item = { type: string };
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: "quote"; items: Item[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const firstInsuranceSurcharge = (premium: number): number => premium / 10;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	export const runScenario = (scenario: Scenario): ScenarioResult => {
24	  const items = scenario.steps[0].items;
25	  const basePremium = items.reduce(
26	    (total, item) => total + BASE_PREMIUMS[item.type],
27	    0,
28	  );
29	  return {
30	    results: [
31	      {
32	        premium:
33	          basePremium + firstInsuranceSurcharge(basePremium) + PROCESSING_FEE,
34	      },
35	    ],
36	  };
37	};
